// --- types.d.ts ---
// types.d.ts
import { ReactNode } from 'react';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F' | string;
  forecast: ForecastItem[];
}

export interface HookReturn {
  formattedTemp: string;
  formattedHumidity: string;
  formattedWind: string;
  displayUnit: string;
  conditionIcon: string;
  forecastItems: ForecastItem[];
}

export interface WeatherHeaderProps {
  city: string;
  condition: string;
}

export interface WeatherMainProps {
  temperature: string;
  condition: string;
  icon: string;
}

export interface WeatherStatsProps {
  humidity: string;
  windSpeed: string;
}

export interface ForecastStripProps {
  forecast: ForecastItem[];
  unit: string;
}

export interface ForecastDayProps {
  item: ForecastItem;
  unit: string;
}

// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const WEATHER_ICONS: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  'partly-cloudy': '⛅',
  rainy: '🌧️',
  snowy: '❄️',
  stormy: '⛈️',
};

export const UNIT_SYMBOLS: Record<string, string> = {
  C: '°C',
  F: '°F',
};

export const LABELS = {
  HUMIDITY: 'Humidity',
  WIND_SPEED: 'Wind Speed',
};

export const DEFAULT_UNIT = 'C';


// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useMemo } from 'react';
import type { WeatherCardProps as Props, HookReturn } from './types';

export function useComponent(props: Props): HookReturn {
  const displayUnit = useMemo(() => {
    return props.unit === 'F' ? '°F' : '°C';
  }, [props.unit]);

  const formattedTemp = useMemo(() => {
    return `${Math.round(props.temperature)}${displayUnit}`;
  }, [props.temperature, displayUnit]);

  const formattedHumidity = useMemo(() => {
    return `${props.humidity}%`;
  }, [props.humidity]);

  const formattedWind = useMemo(() => {
    const label = props.unit === 'F' ? ' mph' : ' km/h';
    return `${props.windSpeed}${label}`;
  }, [props.windSpeed, props.unit]);

  const conditionIcon = useMemo(() => {
    const condition = (props.condition || '').toLowerCase();
    if (condition === 'sunny') return '☀️';
    if (condition === 'cloudy') return '☁️';
    if (condition === 'rainy') return '🌧️';
    if (condition === 'snowy') return '❄️';
    if (condition === 'stormy') return '⛈️';
    return '🌡️';
  }, [props.condition]);

  return {
    formattedTemp,
    formattedHumidity,
    formattedWind,
    displayUnit,
    conditionIcon,
    forecastItems: props.forecast,
  };
}


