// components/WeatherHeader.tsx — reusable sub-component
import React from 'react';
import { Stack, Text, Heading } from '@ggui-ai/design/primitives';
import type { WeatherHeaderProps } from './types';

export function WeatherHeader({ city }: WeatherHeaderProps) {
  const formattedDate = new Intl.DateTimeFormat('en-US', {
    weekday: 'long',
    month: 'short',
    day: 'numeric',
  }).format(new Date());

  return (
    <Stack gap="var(--ggui-spacing-1)">
      <Heading level={2} color="var(--ggui-color-onSurface)">
        {city}
      </Heading>
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
        {formattedDate}
      </Text>
    </Stack>
  );
}


