// components/ForecastStrip.tsx — reusable sub-component
import React from 'react';
import { Stack, Row, Divider, Text } from '@ggui-ai/design/primitives';
import type { ForecastStripProps, ForecastDayProps } from './types';

/**
 * Sub-component for rendering an individual day's forecast.
 */
function ForecastDay({ item, unit }: ForecastDayProps) {
  return (
    <Stack align="center" gap={4}>
      <Text variant="label">{item.day}</Text>
      <Text size="2xl">{item.icon}</Text>
      <Stack direction="horizontal" gap={4} align="center">
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {item.high}°{unit}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {item.low}°{unit}
        </Text>
      </Stack>
    </Stack>
  );
}

export function ForecastStrip({ forecast, unit }: ForecastStripProps) {
  return (
    <section aria-label="5-day forecast" style={{ padding: 'var(--ggui-spacing-4)' }}>
      <Stack gap={16}>
        <Divider margin={0} />
        <Row justify="between">
          {forecast.map((item, index) => (
            <ForecastDay key={index} item={item} unit={unit} />
          ))}
        </Row>
      </Stack>
    </section>
  );
}


