import React from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import type { Props, HookReturn } from './types';
import { WeatherHeader, WeatherMain, WeatherStats, ForecastStrip } from './components';

export function ComponentUI(props: Props & HookReturn) {
  const { 
    city, 
    condition, 
    formattedTemp, 
    formattedHumidity, 
    formattedWind, 
    displayUnit, 
    conditionIcon, 
    forecastItems 
  } = props;

  return (
    <Container maxWidth="400px" center padding="var(--ggui-spacing-6, 24px)">
      <Card 
        padding="var(--ggui-spacing-6, 24px)" 
        shadow="md" 
        radius="lg"
      >
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <WeatherHeader city={city} condition={condition} />
          <WeatherMain temperature={formattedTemp} condition={condition} icon={conditionIcon} />
          <WeatherStats humidity={formattedHumidity} windSpeed={formattedWind} />
          <Divider margin={0} />
          <ForecastStrip forecast={forecastItems} unit={displayUnit} />
        </Stack>
      </Card>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
